import { getServerSession } from "next-auth";
import { authOptions } from "../lib/auth";
import { redirect } from "next/navigation";
import { prisma } from "../lib/prisma";
import SymptomsPieChart from "../components/SymptomsPieChart";

export default async function DashboardPage() {
  const session = await getServerSession(authOptions);
  
  // ตรวจสอบความถูกต้องของเซสชันก่อนดึงข้อมูล
  if (!session || !session.user?.email) {
    redirect("/login");
  }

  // กำหนดช่วงเวลาของเดือนปัจจุบันเพื่อดึงข้อมูล
  const now = new Date();
  const firstDayOfMonth = new Date(now.getFullYear(), now.getMonth(), 1);
  const lastDayOfMonth = new Date(now.getFullYear(), now.getMonth() + 1, 0);

  // ดึงข้อมูลบันทึกสุขภาพจากฐานข้อมูลโดยใช้ Email เป็นตัวอ้างอิง
  const records = await prisma.healthRecord.findMany({
    where: {
      author: { email: session.user.email },
      date: {
        gte: firstDayOfMonth,
        lte: lastDayOfMonth,
      },
    },
  });

  // คำนวณสถิติเพื่อนำไปแสดงผลบน Key Metrics
  const totalRecords = records.length;
  const stressAvg = totalRecords > 0 
    ? (records.reduce((acc, curr) => acc + curr.stressLevel, 0) / totalRecords).toFixed(1) 
    : "0.0";
  const stretchCount = records.filter(r => r.tookBreaks).length;

  // ค้นหาอาการที่พบบ่อยที่สุด
  const symptoms = [
    { label: "ปวดคอ", count: records.filter(r => r.neckPain).length },
    { label: "ปวดหลัง", count: records.filter(r => r.backPain).length },
    { label: "ตาล้า", count: records.filter(r => r.eyeStrain).length },
    { label: "ปวดข้อมือ", count: records.filter(r => r.wristPain).length },
    { label: "ปวดศีรษะ", count: records.filter(r => r.headache).length },
  ];
  
  // ป้องกันการแก้ไข Array ต้นฉบับและตรวจสอบว่ามีอาการเกิดขึ้นจริงหรือไม่
  const sortedSymptoms = [...symptoms].sort((a, b) => b.count - a.count);
  const topSymptom = sortedSymptoms[0];
  const hasSymptoms = topSymptom.count > 0;

  return (
    <section className="container" style={{ marginTop: '40px', paddingBottom: '50px' }}>
      
      {/* ส่วนหัวของระบบวิเคราะห์ข้อมูล */}
      <header style={{ borderBottom: '2px solid #e2e8f0', paddingBottom: '20px', marginBottom: '30px', display: 'flex', justifyContent: 'space-between', alignItems: 'flex-end', flexWrap: 'wrap', gap: '15px' }}>
        <div>
          <h1 style={{ marginBottom: '8px', fontSize: '24px', color: '#0f172a' }}>
            แผงควบคุมและวิเคราะห์ข้อมูลสุขภาพ
          </h1>
          <p className="muted" style={{ margin: 0, fontSize: '15px' }}>
            รายงานสรุปพฤติกรรมประจำเดือน (Monthly Health Analytics) <br/>
            ผู้ใช้งานระบบ: <span style={{ fontWeight: '600', color: '#334155' }}>{session.user.name || session.user.email}</span>
          </p>
        </div>

        {/* แถบเลือกเดือนแบบมินิมอล */}
        <div style={{ display: 'flex', alignItems: 'center', gap: '10px', background: '#f8fafc', padding: '8px 15px', borderRadius: '8px', border: '1px solid #e2e8f0' }}>
          <label htmlFor="month-select" style={{ fontSize: '14px', fontWeight: '600', color: '#475569', margin: 0 }}>เลือกเดือน:</label>
          <select 
            id="month-select" 
            style={{ padding: '6px 10px', borderRadius: '6px', border: '1px solid #cbd5e1', background: '#ffffff', fontSize: '14px', cursor: 'pointer', outline: 'none', color: '#0f172a', fontWeight: '500' }}
          >
            <option>กุมภาพันธ์ 2026 (ปัจจุบัน)</option>
          </select>
        </div>
      </header>

      {/* ส่วนแสดงข้อมูลสถิติหลักจากฐานข้อมูล */}
      <div className="grid" style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: '20px', marginBottom: '30px' }}>
        
        {/* สรุปอาการเด่น */}
        <article className="card" style={{ borderTop: '4px solid #ef4444', padding: '24px', background: '#ffffff', borderRadius: '12px', boxShadow: '0 4px 6px -1px rgba(0,0,0,0.05)' }}>
          <h3 style={{ color: '#64748b', fontSize: '13px', textTransform: 'uppercase', letterSpacing: '0.5px', marginTop: 0 }}>
            กลุ่มอาการที่พบสูงสุดในเดือนนี้
          </h3>
          <p style={{ fontSize: '26px', fontWeight: 'bold', margin: '15px 0', color: '#0f172a' }}>
            {hasSymptoms ? topSymptom.label : "ยังไม่มีข้อมูลอาการ"}
          </p>
          <div style={{ background: '#fee2e2', color: '#b91c1c', padding: '10px 12px', borderRadius: '6px', fontSize: '13px', fontWeight: '500' }}>
            สถานะ: ตรวจพบความเสี่ยงสะสม {hasSymptoms ? topSymptom.count : 0} วัน
          </div>
        </article>

        {/* ค่าเฉลี่ยความเหนื่อยล้า */}
        <article className="card" style={{ borderTop: '4px solid #f59e0b', padding: '24px', background: '#ffffff', borderRadius: '12px', boxShadow: '0 4px 6px -1px rgba(0,0,0,0.05)' }}>
          <h3 style={{ color: '#64748b', fontSize: '13px', textTransform: 'uppercase', letterSpacing: '0.5px', marginTop: 0 }}>
            ดัชนีความเหนื่อยล้าเฉลี่ยประจำเดือน
          </h3>
          <div style={{ display: 'flex', alignItems: 'baseline', gap: '8px', margin: '15px 0' }}>
            <span style={{ fontSize: '28px', fontWeight: 'bold', color: '#0f172a' }}>{stressAvg}</span>
            <span style={{ fontSize: '16px', color: '#64748b' }}>/ 5.0</span>
          </div>
          <div style={{ background: '#fef3c7', color: '#b45309', padding: '10px 12px', borderRadius: '6px', fontSize: '13px', fontWeight: '500' }}>
            สถานะ: {Number(stressAvg) > 3 ? "ควรหาเวลาพักผ่อนเพิ่ม" : "อยู่ในเกณฑ์ปกติ"}
          </div>
        </article>

        {/* ความถี่ในการยืดกล้ามเนื้อ */}
        <article className="card" style={{ borderTop: '4px solid #10b981', padding: '24px', background: '#ffffff', borderRadius: '12px', boxShadow: '0 4px 6px -1px rgba(0,0,0,0.05)' }}>
          <h3 style={{ color: '#64748b', fontSize: '13px', textTransform: 'uppercase', letterSpacing: '0.5px', marginTop: 0 }}>
            ความสม่ำเสมอในการยืดกล้ามเนื้อ
          </h3>
          <div style={{ display: 'flex', alignItems: 'baseline', gap: '8px', margin: '15px 0' }}>
            <span style={{ fontSize: '28px', fontWeight: 'bold', color: '#0f172a' }}>{stretchCount}</span>
            <span style={{ fontSize: '16px', color: '#64748b' }}>/ {totalRecords} วันที่บันทึก</span>
          </div>
          <div style={{ background: '#d1fae5', color: '#047857', padding: '10px 12px', borderRadius: '6px', fontSize: '13px', fontWeight: '500' }}>
            ข้อเสนอแนะ: {totalRecords === 0 ? "ยังไม่มีการบันทึก" : stretchCount < (totalRecords/2) ? "ควรเพิ่มความถี่เพื่อสุขภาพ" : "รักษาวินัยได้ดีเยี่ยม"}
          </div>
        </article>
      </div>

      {/* ส่วนแสดงกราฟสัดส่วนอาการ */}
      <div className="row">
        <article className="card" style={{ padding: '24px', background: '#ffffff', borderRadius: '12px', boxShadow: '0 4px 6px -1px rgba(0,0,0,0.05)' }}>
             <header style={{ marginBottom: '20px', borderBottom: '1px solid #f1f5f9', paddingBottom: '10px' }}>
                <h3 style={{ margin: 0, color: '#0f172a', fontSize: '18px' }}>สัดส่วนการกระจายตัวของอาการ (Symptom Distribution)</h3>
                <p className="muted" style={{ margin: '5px 0 0 0', fontSize: '14px' }}>วิเคราะห์เปรียบเทียบความถี่ของอาการจากข้อมูลจริงในเดือนนี้</p>
             </header>
             <SymptomsPieChart data={symptoms} />
        </article>
      </div>

    </section>
  );
}